import java.lang.annotation.*;
import java.lang.reflect.*;
@Retention(RetentionPolicy.RUNTIME)
@interface Tag { String value(); }
@Tag("hello")
public class AnnotDemo {
    @Tag("world")
    void method() {}
    public static void main(String[] args) throws Exception {
        Tag classTag = AnnotDemo.class.getAnnotation(Tag.class);
        System.out.println(classTag.value());
        Tag methodTag = AnnotDemo.class.getDeclaredMethod("method").getAnnotation(Tag.class);
        System.out.println(methodTag.value());
    }
}
